(121, 1, '2026-04-09 03:33:57', '2026-04-09 00:33:57', '{\n    \"head-blog::background_preset\": {\n        \"value\": \"custom\",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 00:33:57\"\n    },\n    \"head-blog::background_position_x\": {\n        \"value\": \"center\",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 00:33:57\"\n    },\n    \"head-blog::background_position_y\": {\n        \"value\": \"center\",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 00:33:57\"\n    },\n    \"head-blog::background_repeat\": {\n        \"value\": \"no-repeat\",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 00:33:57\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', 'edeee7f7-905c-4b44-86b0-06370c15eb45', '', '', '2026-04-09 03:33:57', '2026-04-09 00:33:57', '', 0, 'http://localhost/node.js/?p=121', 0, 'customize_changeset', '', 0),
