"Yaz\\u0131\",\n            \"url\": \"http://localhost/node.js/?p=203\",\n            \"title\": \"Veri Y\\u00f6netimi ve API Geli\\u015ftirme\",\n            \"target\": \"\",\n            \"attr_title\": \"\",\n            \"description\": \"\",\n            \"classes\": \"\",\n            \"xfn\": \"\",\n            \"nav_menu_term_id\": 6,\n            \"position\": 19,\n            \"status\": \"publish\",\n            \"_invalid\": false,\n            \"original_title\": \"Veri Y\\u00f6netimi ve API Geli\\u015ftirme\"\n        },\n        \"type\": \"nav_menu_item\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-10 16:57:48\"\n    },\n    \"nav_menu_item[286]\": {\n        \"value\": {\n            \"menu_item_parent\": 0,\n            \"object_id\": 223,\n            \"object\": \"post\",\n            \"type\": \"post_type\",\n            \"type_label\": \"Yaz\\u0131\",\n            \"url\": \"http://localhost/node.js/?p=223\",\n            \"title\": \"\\u0130leri Seviye (G\\u00fcvenlik ve Real-Time)\",\n            \"target\": \"\",\n            \"attr_title\": \"\",\n            \"description\": \"\",\n            \"classes\": \"\",\n            \"xfn\": \"\",\n            \"nav_menu_term_id\": 6,\n            \"position\": 29,\n            \"status\": \"publish\",\n            \"_invalid\": false,\n            \"original_title\": \"\\u0130leri Seviye (G\\u00fcvenlik ve Real-Time)\"\n        },\n        \"type\": \"nav_menu_item\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-10 16:57:48\"\n    },\n    \"nav_menu_item[293]\": {\n        \"value\": {\n            \"menu_item_parent\": 0,\n            \"object_id\": 237,\n            \"object\": \"post\",\n            \"type\": \"post_type\",\n            \"type_label\": \"Yaz\\u0131\",\n            \"url\": \"http://localhost/node.js/?p=237\",\n            \"title\": \"Uzmanl\\u0131k ve Canl\\u0131ya Alma (Deployment)\",\n            \"target\": \"\",\n            \"attr_title\": \"\",\n            \"description\": \"\",\n            \"classes\": \"\",\n            \"xfn\": \"\",\n            \"nav_menu_term_id\": 6,\n            \"position\": 36,\n            \"status\": \"publish\",\n            \"_invalid\": false,\n            \"original_title\": \"Uzmanl\\u0131k ve Canl\\u0131ya Alma (Deployment)\"\n        },\n        \"type\": \"nav_menu_item\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-10 16:57:48\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', '392961eb-a2c1-4285-9759-5cba49514d1b', '', '', '2026-04-10 19:57:48', '2026-04-10 16:57:48', '', 0, 'http://localhost/node.js/?p=304', 0, 'customize_changeset', '', 0),
